import{bQ as a,aL as s,u as i,G as d}from"./chunks/framework.D06dwy5q.js";const e="/kb/assets/01-file-to-table.SP9h6i4a.png",r="/kb/assets/02-transaction-all-or-rollback.D-aibATE.png",h="/kb/assets/03-index-directory.BcynrdE9.png",l="/kb/assets/04-replication-backup-not-same.C5-FBjKW.png",b=JSON.parse('{"title":"第 6 讲｜数据库的出现","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/06-数据库出现.md","filePath":"00.互联网与架构基础/06-数据库出现.md","lastUpdated":null}'),n={name:"00.互联网与架构基础/06-数据库出现.md"};function o(p,t,k,E,c,g){return s(),i("div",null,[...t[0]||(t[0]=[d('<h1 id="第-6-讲-数据库的出现" tabindex="-1">第 6 讲｜数据库的出现 <a class="header-anchor" href="#第-6-讲-数据库的出现" aria-label="Permalink to &quot;第 6 讲｜数据库的出现&quot;">​</a></h1><p>数据量少的时候,JSON、CSV、纯文本文件就能解决问题——简单、直接、不需要任何额外组件。但场景一旦升级到&quot;多人同时读写、按条件查询、按时序追加&quot;,文件方案会迅速暴露一系列根本性缺陷:并发写入互相覆盖、按条件查找要扫整个文件、误删后恢复困难、字段格式难以统一校验。<strong>数据库就是为解决这一系列问题而设计的系统</strong>。</p><p>本讲从文件方案的局限出发,讲清楚数据库的核心概念:表、SQL、事务、索引、缓存、复制与备份。这些是后续所有业务架构(单机、集群、微服务、分布式)的共同基础。</p><h2 id="一、文件方案的局限" tabindex="-1">一、文件方案的局限 <a class="header-anchor" href="#一、文件方案的局限" aria-label="Permalink to &quot;一、文件方案的局限&quot;">​</a></h2><p>把文件方案的问题逐一列出,数据库的价值就一目了然:</p><p><img src="'+e+'" alt="文件方案混乱后需要数据库表来管理数据"></p><table tabindex="0"><thead><tr><th>问题</th><th>具体表现</th></tr></thead><tbody><tr><td>查询慢</td><td>按条件查找需要从头扫整个文件,百万行级数据基本不可用</td></tr><tr><td>并发难</td><td>两个进程同时写文件,后写的覆盖先写的,没有并发控制机制</td></tr><tr><td>格式脆弱</td><td>JSON 少一个逗号、CSV 多一个换行,整份文件无法解析</td></tr><tr><td>约束少</td><td>字段类型、必填、唯一性、外键关联,全靠业务代码自己校验</td></tr><tr><td>恢复麻烦</td><td>误删一行后只能从备份恢复,且备份可能也已损坏</td></tr><tr><td>事务缺失</td><td>&quot;扣库存 + 写订单&quot; 这种必须整体成功或失败的操作无法保证原子性</td></tr></tbody></table><p>数据库的&quot;表&quot;看起来与结构化文件类似——都是行和列——但多出了<strong>字段类型、约束、索引、事务、查询语言</strong>这些能力。这些机制是文件方案天然不具备的。</p><h2 id="二、表与-sql" tabindex="-1">二、表与 SQL <a class="header-anchor" href="#二、表与-sql" aria-label="Permalink to &quot;二、表与 SQL&quot;">​</a></h2><h3 id="表的结构" tabindex="-1">表的结构 <a class="header-anchor" href="#表的结构" aria-label="Permalink to &quot;表的结构&quot;">​</a></h3><p>数据库中最基本的概念是<strong>表</strong>(table)。表由若干列(column)和若干行(row)组成:</p><table tabindex="0"><thead><tr><th>id</th><th>name</th><th>email</th><th>status</th><th>created_at</th></tr></thead><tbody><tr><td>1</td><td>alice</td><td><a href="mailto:alice@example.com" target="_blank" rel="noreferrer">alice@example.com</a></td><td>active</td><td>2026-06-10 09:00</td></tr><tr><td>2</td><td>bob</td><td><a href="mailto:bob@example.com" target="_blank" rel="noreferrer">bob@example.com</a></td><td>inactive</td><td>2026-06-10 10:30</td></tr></tbody></table><p>每一行代表一条记录,每一列代表一个字段。<strong>字段在建表时声明类型</strong>:<code>id</code> 是整数、<code>name</code> 是字符串、<code>created_at</code> 是时间戳——类型在写入时被强制校验,不符合类型的数据会被拒绝。</p><h3 id="sql-操作数据库的标准语言" tabindex="-1">SQL:操作数据库的标准语言 <a class="header-anchor" href="#sql-操作数据库的标准语言" aria-label="Permalink to &quot;SQL:操作数据库的标准语言&quot;">​</a></h3><p>SQL(Structured Query Language)是关系型数据库的标准操作语言,核心动词:</p><table tabindex="0"><thead><tr><th>SQL 关键字</th><th>操作</th><th>示例</th></tr></thead><tbody><tr><td><code>SELECT</code></td><td>查询</td><td><code>SELECT name FROM users WHERE id = 1;</code></td></tr><tr><td><code>INSERT</code></td><td>插入</td><td><code>INSERT INTO users (name, email) VALUES (...);</code></td></tr><tr><td><code>UPDATE</code></td><td>修改</td><td><code>UPDATE users SET status = &#39;inactive&#39; WHERE id = 1;</code></td></tr><tr><td><code>DELETE</code></td><td>删除</td><td><code>DELETE FROM users WHERE id = 1;</code></td></tr><tr><td><code>CREATE TABLE</code></td><td>建表</td><td><code>CREATE TABLE users (id INT PRIMARY KEY, ...);</code></td></tr><tr><td><code>JOIN</code></td><td>多表关联</td><td><code>SELECT u.name, t.title FROM users u JOIN tasks t ON t.user_id = u.id;</code></td></tr><tr><td><code>GROUP BY</code></td><td>聚合</td><td><code>SELECT status, COUNT(*) FROM users GROUP BY status;</code></td></tr></tbody></table><p>SQL 语法学起来不难,但<strong>写好 SQL 是另一回事</strong>——索引设计、查询优化、连接池管理、慢查询定位是数据库相关工作的核心技能,需要长期积累。</p><h3 id="数据库的几大类别" tabindex="-1">数据库的几大类别 <a class="header-anchor" href="#数据库的几大类别" aria-label="Permalink to &quot;数据库的几大类别&quot;">​</a></h3><p>根据数据结构和场景,数据库分为几大类:</p><table tabindex="0"><thead><tr><th>类别</th><th>代表</th><th>数据结构</th><th>典型用途</th></tr></thead><tbody><tr><td>关系型</td><td>MySQL、PostgreSQL、Oracle、SQL Server</td><td>行列表,固定 schema</td><td>用户、订单、权限、审计等核心业务数据</td></tr><tr><td>文档型</td><td>MongoDB、CouchDB</td><td>JSON 文档</td><td>内容管理、嵌套结构、schema 易变化</td></tr><tr><td>键值型</td><td>Redis、Memcached</td><td>key-value</td><td>缓存、会话、计数器、消息队列</td></tr><tr><td>列式</td><td>ClickHouse、Cassandra</td><td>按列存储</td><td>OLAP 分析、大数据聚合</td></tr><tr><td>检索型</td><td>Elasticsearch、OpenSearch</td><td>倒排索引</td><td>全文检索、日志检索</td></tr><tr><td>时序型</td><td>InfluxDB、TimescaleDB、Prometheus</td><td>时间戳 + 标签 + 数值</td><td>监控指标、IoT</td></tr><tr><td>图数据库</td><td>Neo4j、JanusGraph</td><td>节点 + 边</td><td>社交关系、推荐、风控</td></tr></tbody></table><p>业务系统通常<strong>同时使用多种数据库</strong>:MySQL 存核心业务、Redis 做缓存、Elasticsearch 做搜索、ClickHouse 做分析,各自负责擅长的场景。</p><h2 id="三、事务-必须整体成功或失败" tabindex="-1">三、事务:必须整体成功或失败 <a class="header-anchor" href="#三、事务-必须整体成功或失败" aria-label="Permalink to &quot;三、事务:必须整体成功或失败&quot;">​</a></h2><p>事务(Transaction)是数据库最核心的能力之一。它解决的问题是:<strong>一组操作必须整体成功或整体失败,不能停在中间状态</strong>。</p><p><img src="'+r+`" alt="事务要求一组动作整体成功或整体回滚"></p><h3 id="转账场景的经典例子" tabindex="-1">转账场景的经典例子 <a class="header-anchor" href="#转账场景的经典例子" aria-label="Permalink to &quot;转账场景的经典例子&quot;">​</a></h3><p>最经典的例子是转账:A 账户扣 100,B 账户加 100。如果扣完 A 的钱程序崩溃,B 那边没加上,<strong>钱凭空消失了 100</strong>——这种状态在金融系统里是绝对不能出现的。</p><p>事务把&quot;扣 A + 加 B&quot;包在一起,<strong>要么两步都成功提交,要么任何一步失败就整体回滚</strong>:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BEGIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;                                                  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 开始事务</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> accounts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> balance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> balance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;A&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> accounts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> balance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> balance </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;B&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COMMIT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;                                                  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 全部成功,提交</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 或</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ROLLBACK</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;                                                </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 任一步失败,回滚</span></span></code></pre></div><h3 id="acid-四特性" tabindex="-1">ACID 四特性 <a class="header-anchor" href="#acid-四特性" aria-label="Permalink to &quot;ACID 四特性&quot;">​</a></h3><p>事务保证的四个特性合称 ACID:</p><table tabindex="0"><thead><tr><th>特性</th><th>含义</th></tr></thead><tbody><tr><td><strong>A</strong>tomicity 原子性</td><td>一组操作整体成功或整体失败,不会停在中间状态</td></tr><tr><td><strong>C</strong>onsistency 一致性</td><td>操作前后数据必须满足所有约束(外键、唯一、检查约束)</td></tr><tr><td><strong>I</strong>solation 隔离性</td><td>并发事务之间的影响受控制,看起来像串行执行</td></tr><tr><td><strong>D</strong>urability 持久性</td><td>提交后的数据不因进程崩溃或断电丢失</td></tr></tbody></table><h3 id="隔离级别-并发事务的可见性控制" tabindex="-1">隔离级别:并发事务的可见性控制 <a class="header-anchor" href="#隔离级别-并发事务的可见性控制" aria-label="Permalink to &quot;隔离级别:并发事务的可见性控制&quot;">​</a></h3><p>并发执行的事务之间,如何看到对方的修改,由<strong>隔离级别</strong>控制。SQL 标准定义了四种:</p><table tabindex="0"><thead><tr><th>隔离级别</th><th>脏读</th><th>不可重复读</th><th>幻读</th><th>性能</th></tr></thead><tbody><tr><td>Read Uncommitted</td><td>可能</td><td>可能</td><td>可能</td><td>最高</td></tr><tr><td>Read Committed</td><td>不会</td><td>可能</td><td>可能</td><td>高</td></tr><tr><td>Repeatable Read</td><td>不会</td><td>不会</td><td>可能</td><td>中</td></tr><tr><td>Serializable</td><td>不会</td><td>不会</td><td>不会</td><td>最低</td></tr></tbody></table><p>MySQL InnoDB 默认 Repeatable Read,PostgreSQL 默认 Read Committed。隔离级别越高,并发性能越差——通常不动默认值,有特殊需求时显式调整。</p><h3 id="业务场景中需要事务的常见动作" tabindex="-1">业务场景中需要事务的常见动作 <a class="header-anchor" href="#业务场景中需要事务的常见动作" aria-label="Permalink to &quot;业务场景中需要事务的常见动作&quot;">​</a></h3><ul><li><strong>金融</strong>:转账、扣款、结算</li><li><strong>电商</strong>:扣库存 + 生成订单 + 写入支付流水</li><li><strong>任务系统</strong>:创建任务 + 写审计日志 + 发送通知</li><li><strong>配置变更</strong>:更新配置 + 记录版本号</li><li><strong>审批流</strong>:状态变更 + 写入审批历史</li></ul><p>凡是&quot;一组关联操作不能停在中间状态&quot;的场景,都需要事务包裹。</p><h2 id="四、索引" tabindex="-1">四、索引 <a class="header-anchor" href="#四、索引" aria-label="Permalink to &quot;四、索引&quot;">​</a></h2><p><img src="`+h+`" alt="索引像目录帮助数据库少翻表"></p><h3 id="索引是数据库的查找目录" tabindex="-1">索引是数据库的查找目录 <a class="header-anchor" href="#索引是数据库的查找目录" aria-label="Permalink to &quot;索引是数据库的查找目录&quot;">​</a></h3><p>索引(Index)是数据库为某些字段建立的额外查找结构,作用<strong>类似于书的目录</strong>——没有索引,找一个用户要翻整本书(全表扫描);有索引,直接定位到第几页(索引查找)。</p><p>最常见的索引数据结构是 <strong>B+ 树</strong>(MySQL、PostgreSQL 默认),还有哈希索引、全文索引、空间索引等。索引的本质是<strong>用额外的存储和写入开销,换取查询速度</strong>。</p><h3 id="索引带来的性能差异" tabindex="-1">索引带来的性能差异 <a class="header-anchor" href="#索引带来的性能差异" aria-label="Permalink to &quot;索引带来的性能差异&quot;">​</a></h3><p>一个具体例子:任务表 100 万行,接口要查询&quot;状态为 failed 且最近 1 天创建&quot;的任务。</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tasks </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;failed&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;2026-06-22&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>无索引时:数据库扫描全表 100 万行,逐条判断,通常需要数秒。</p><p>加索引后:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> INDEX</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> idx_status_created</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tasks (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, created_at);</span></span></code></pre></div><p>数据库通过索引直接定位到满足条件的行,通常在几十毫秒内返回。</p><p><strong>这种&quot;加索引后接口从 5 秒变成 50 毫秒&quot;的提升在慢 SQL 优化中非常常见</strong>——绝大多数性能问题的根因都是缺少合适的索引。</p><h3 id="索引不是越多越好" tabindex="-1">索引不是越多越好 <a class="header-anchor" href="#索引不是越多越好" aria-label="Permalink to &quot;索引不是越多越好&quot;">​</a></h3><p>索引带来代价:</p><table tabindex="0"><thead><tr><th>代价</th><th>影响</th></tr></thead><tbody><tr><td>占用磁盘空间</td><td>每个索引都是一份额外的数据</td></tr><tr><td>拖慢写入</td><td>INSERT/UPDATE/DELETE 时必须同步维护所有相关索引</td></tr><tr><td>占用内存</td><td>查询时索引需要加载到内存才高效</td></tr></tbody></table><p>一般原则:</p><ul><li><strong>经常出现在 WHERE、JOIN、ORDER BY 中的字段</strong>适合建索引</li><li><strong>极少查询、频繁更新的字段</strong>不适合建索引</li><li><strong>重复值很多的字段</strong>(如性别)单独建索引意义不大</li><li><strong>联合索引比多个单字段索引更高效</strong>——但联合索引有&quot;最左前缀&quot;原则(详见 MySQL 文档)</li></ul><h3 id="慢查询排查的标准流程" tabindex="-1">慢查询排查的标准流程 <a class="header-anchor" href="#慢查询排查的标准流程" aria-label="Permalink to &quot;慢查询排查的标准流程&quot;">​</a></h3><p>接口慢且怀疑数据库时,标准排查路径:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 1. 看执行计划,确认是否走索引</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">EXPLAIN </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tasks </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;failed&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;2026-06-22&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 看 type 列:ALL 全表扫描、index 索引扫描、range 范围扫描、ref 索引等值</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 2. 看慢查询日志(MySQL)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW VARIABLES </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;slow_query_log%&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 3. 看当前正在执行的慢查询</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW FULL PROCESSLIST;</span></span></code></pre></div><p>绝大多数慢查询的根因是:<strong>应该走索引但走了全表扫描</strong>——执行计划的 <code>type = ALL</code> 是最直接的信号。</p><h2 id="五、缓存" tabindex="-1">五、缓存 <a class="header-anchor" href="#五、缓存" aria-label="Permalink to &quot;五、缓存&quot;">​</a></h2><p>数据库再快也有上限。<strong>有些数据被频繁读取但很少变化,每次都查数据库会造成不必要的负担</strong>。缓存就是把热数据放在更快的存储(通常是 Redis)中,应用先查缓存,缓存未命中再查数据库并回填缓存。</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20participant%20App%20as%20%E5%BA%94%E7%94%A8%0A%20%20participant%20Cache%20as%20%E7%BC%93%E5%AD%98(Redis)%0A%20%20participant%20DB%20as%20%E6%95%B0%E6%8D%AE%E5%BA%93%0A%0A%20%20App-%3E%3ECache%3A%20GET%20user%3A1001%0A%20%20alt%20%E7%BC%93%E5%AD%98%E5%91%BD%E4%B8%AD%0A%20%20%20%20Cache--%3E%3EApp%3A%20%E8%BF%94%E5%9B%9E%E6%95%B0%E6%8D%AE%0A%20%20else%20%E7%BC%93%E5%AD%98%E6%9C%AA%E5%91%BD%E4%B8%AD%0A%20%20%20%20Cache--%3E%3EApp%3A%20nil%0A%20%20%20%20App-%3E%3EDB%3A%20SELECT%20*%20FROM%20users%20WHERE%20id%20%3D%201001%0A%20%20%20%20DB--%3E%3EApp%3A%20%E7%94%A8%E6%88%B7%E6%95%B0%E6%8D%AE%0A%20%20%20%20App-%3E%3ECache%3A%20SET%20user%3A1001%20...%20EX%20300%0A%20%20%20%20Note%20over%20App%3A%20%E5%90%8C%E6%97%B6%E5%9B%9E%E5%A1%AB%E7%BC%93%E5%AD%98%0A%20%20end%0A"></div><h3 id="适合缓存的数据特征" tabindex="-1">适合缓存的数据特征 <a class="header-anchor" href="#适合缓存的数据特征" aria-label="Permalink to &quot;适合缓存的数据特征&quot;">​</a></h3><ul><li><strong>读多写少</strong> — 读写比例 10:1 以上</li><li><strong>变化不频繁</strong> — 几分钟到几小时不变</li><li><strong>可容忍轻微延迟</strong> — 缓存与数据库可能短暂不一致</li></ul><p>典型场景:用户权限、配置项、字典表、热门商品、排行榜、统计接口的聚合结果。</p><h3 id="不适合缓存的数据" tabindex="-1">不适合缓存的数据 <a class="header-anchor" href="#不适合缓存的数据" aria-label="Permalink to &quot;不适合缓存的数据&quot;">​</a></h3><ul><li>强一致要求的数据(如账户余额)</li><li>写多读少的数据</li><li>数据量极大且访问随机(命中率低)</li></ul><h3 id="缓存引入的四个经典问题" tabindex="-1">缓存引入的四个经典问题 <a class="header-anchor" href="#缓存引入的四个经典问题" aria-label="Permalink to &quot;缓存引入的四个经典问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>含义</th><th>处理</th></tr></thead><tbody><tr><td>缓存穿透</td><td>大量查询根本不存在的数据,缓存里没有,全部打到数据库</td><td>缓存空值(短 TTL)、布隆过滤器</td></tr><tr><td>缓存击穿</td><td>某个热点 key 突然过期,瞬间大量请求同时查数据库</td><td>互斥锁、热点 key 永不过期</td></tr><tr><td>缓存雪崩</td><td>大量 key 同时过期(或缓存整体挂),数据库压力暴涨</td><td>过期时间加随机抖动、多级缓存、降级</td></tr><tr><td>数据不一致</td><td>数据库更新了但缓存还是旧值</td><td>主动失效、延迟双删、订阅 binlog 同步</td></tr></tbody></table><h3 id="缓存的核心原则-缓存只是优化手段" tabindex="-1">缓存的核心原则:缓存只是优化手段 <a class="header-anchor" href="#缓存的核心原则-缓存只是优化手段" aria-label="Permalink to &quot;缓存的核心原则:缓存只是优化手段&quot;">​</a></h3><p><strong>缓存绝不能作为唯一数据来源</strong>。缓存里丢了数据,系统必须能从数据库恢复出来。把数据只放缓存(不持久化到数据库),Redis 重启或数据被淘汰后业务就瘫了——这不是合理的架构,而是把缓存当数据库用的滥用。</p><p>业务架构的不变量:<strong>数据库是事实来源(source of truth),缓存只是临时副本</strong>。</p><h2 id="六、复制与备份" tabindex="-1">六、复制与备份 <a class="header-anchor" href="#六、复制与备份" aria-label="Permalink to &quot;六、复制与备份&quot;">​</a></h2><p>数据库的高可用和容灾,主要依赖以下三种机制:</p><p><img src="`+l+'" alt="复制和备份覆盖的问题不同，不能互相替代"></p><table tabindex="0"><thead><tr><th>机制</th><th>解决什么问题</th></tr></thead><tbody><tr><td>主从复制</td><td>主库故障时从库可接管;读请求可分摊到从库</td></tr><tr><td>备份</td><td>误删、表损坏、机房整体故障后能恢复数据</td></tr><tr><td>binlog / WAL</td><td>记录所有变更过程,支持基于时间点恢复(PITR)与复制</td></tr></tbody></table><h3 id="主从复制-实时同步" tabindex="-1">主从复制:实时同步 <a class="header-anchor" href="#主从复制-实时同步" aria-label="Permalink to &quot;主从复制:实时同步&quot;">​</a></h3><p>主从复制的工作原理:<strong>主库执行的每一次数据变更,通过 binlog(MySQL)或 WAL(PostgreSQL)同步到从库</strong>,从库重放这些变更以保持数据一致。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20App%5B%22%E5%BA%94%E7%94%A8%22%5D%0A%20%20Master%5B(%22%E4%B8%BB%E5%BA%93%3Cbr%2F%3E%E8%AF%BB%20%2B%20%E5%86%99%22)%5D%0A%20%20Slave1%5B(%22%E4%BB%8E%E5%BA%93%201%3Cbr%2F%3E%E5%8F%AA%E8%AF%BB%22)%5D%0A%20%20Slave2%5B(%22%E4%BB%8E%E5%BA%93%202%3Cbr%2F%3E%E5%8F%AA%E8%AF%BB%22)%5D%0A%0A%20%20App%20--%3E%7C%22%E5%86%99%22%7C%20Master%0A%20%20App%20--%3E%7C%22%E8%AF%BB%22%7C%20Slave1%0A%20%20App%20--%3E%7C%22%E8%AF%BB%22%7C%20Slave2%0A%20%20Master%20-.-%3E%7C%22binlog%20%E5%90%8C%E6%AD%A5%22%7C%20Slave1%0A%20%20Master%20-.-%3E%7C%22binlog%20%E5%90%8C%E6%AD%A5%22%7C%20Slave2%0A"></div><p>主从复制的两个核心用途:</p><ol><li><strong>故障切换</strong>:主库挂了,从库提升为主继续提供服务,业务停机时间可控</li><li><strong>读写分离</strong>:写请求只给主库,读请求分摊到多个从库,扩展读容量</li></ol><h3 id="备份-防御数据损坏" tabindex="-1">备份:防御数据损坏 <a class="header-anchor" href="#备份-防御数据损坏" aria-label="Permalink to &quot;备份:防御数据损坏&quot;">​</a></h3><p>备份是把数据库的某一时刻状态完整保存到独立存储(对象存储、磁带、远程机房)。<strong>备份的核心价值是应对&quot;数据损坏&quot;和&quot;误操作&quot;</strong>——这些场景下复制完全无效。</p><p>常见备份策略:</p><table tabindex="0"><thead><tr><th>策略</th><th>频率</th><th>保留</th></tr></thead><tbody><tr><td>全量备份</td><td>每日 / 每周</td><td>数天至数月</td></tr><tr><td>增量备份</td><td>每小时 / 每天</td><td>配合全量恢复</td></tr><tr><td>binlog 持续归档</td><td>实时</td><td>至少最近一周</td></tr></tbody></table><h3 id="复制不能替代备份" tabindex="-1">复制不能替代备份 <a class="header-anchor" href="#复制不能替代备份" aria-label="Permalink to &quot;复制不能替代备份&quot;">​</a></h3><p><strong>这是必须记住的核心认知</strong>:主从复制是异步的(或半同步)——主库上误删一张表 <code>DROP TABLE users</code>,这个 DROP 操作会被同步到所有从库,<strong>所有副本里这张表都会被删除</strong>。</p><p>这种场景下只有从备份恢复才是出路。复制无法防御:</p><ul><li>误操作:<code>DROP DATABASE</code>、<code>DELETE</code> 未带 WHERE、<code>UPDATE</code> 影响范围错</li><li>应用 bug 写脏数据</li><li>安全事件:被入侵后批量删除/篡改数据</li><li>表结构损坏</li></ul><h3 id="备份不能替代高可用" tabindex="-1">备份不能替代高可用 <a class="header-anchor" href="#备份不能替代高可用" aria-label="Permalink to &quot;备份不能替代高可用&quot;">​</a></h3><p>反过来,<strong>备份恢复需要时间</strong>——几十 GB 的数据库恢复可能需要数十分钟到几小时,期间业务完全不可用。</p><p>如果业务对可用性有要求(如 99.95%),光靠&quot;挂了从备份恢复&quot;远远不够——必须有主从切换、集群方案,保证故障时分钟级甚至秒级切换。</p><h3 id="生产环境的标准配置" tabindex="-1">生产环境的标准配置 <a class="header-anchor" href="#生产环境的标准配置" aria-label="Permalink to &quot;生产环境的标准配置&quot;">​</a></h3><p>生产数据库的合理配置组合:</p><ul><li>主从复制 — 保证主库故障时分钟级切换</li><li>定期全量备份 + 增量 + binlog 归档 — 保证误操作时可恢复到任意时间点</li><li>备份<strong>异地存储</strong> — 防御机房级故障</li><li>定期演练恢复 — 确认备份是真的能用(很多团队备份从没成功恢复过)</li></ul><p><strong>备份未演练 = 没有备份</strong>——只有真正恢复过的备份才是可靠的备份。这是数据库容灾里最容易被忽略但最重要的原则。</p><h3 id="三种机制的覆盖关系" tabindex="-1">三种机制的覆盖关系 <a class="header-anchor" href="#三种机制的覆盖关系" aria-label="Permalink to &quot;三种机制的覆盖关系&quot;">​</a></h3><table tabindex="0"><thead><tr><th>故障类型</th><th>主从复制</th><th>备份</th><th>binlog</th></tr></thead><tbody><tr><td>主库进程崩溃</td><td>✓ 切换从库</td><td>✗ 太慢</td><td>✗ 单独无用</td></tr><tr><td>主库硬件故障</td><td>✓ 切换从库</td><td>△ 可恢复但慢</td><td>✗</td></tr><tr><td>误删数据</td><td>✗ 复制把删除同步走了</td><td>✓ 从备份恢复</td><td>✓ PITR 恢复到删除前</td></tr><tr><td>表结构损坏</td><td>✗ 同上</td><td>✓</td><td>✗</td></tr><tr><td>机房整体故障</td><td>△ 需要异地从库</td><td>✓ 异地备份</td><td>✓</td></tr><tr><td>入侵后数据篡改</td><td>✗</td><td>✓(但需保留时间够长)</td><td>✓</td></tr></tbody></table><p><strong>三种机制必须同时存在</strong>,任一缺失都会让某类故障无法处理。</p>',100)])])}const u=a(n,[["render",o]]);export{b as __pageData,u as default};
